import React from 'react';
import { Feed } from './Feed';
import './styles.css';

export default function App() {
  return (
    <div style={{ padding: '2rem', fontFamily: 'system-ui, sans-serif', maxWidth: '32rem' }}>
      <h1 style={{ marginBottom: '1.5rem' }}>Infinite Feed</h1>
      <Feed apiUrl="/api/posts" pageSize={10} />
    </div>
  );
}

import React, { useState, useEffect, useRef, useCallback } from 'react';
import './styles.css';

interface Post {
  id: number;
  title: string;
  body: string;
  author: string;
}

interface FeedProps {
  apiUrl: string;
  pageSize: number;
}

// TODO: Implement infinite scrolling
// 1. Fetch first page on mount
// 2. IntersectionObserver on sentinel to trigger next page
// 3. Loading, error, and end-of-feed states
// 4. Track pages loaded

export const Feed: React.FC<FeedProps> = ({ apiUrl, pageSize }) => {
  const [posts, setPosts] = useState<Post[]>([]);
  const [page, setPage] = useState(1);
  const [isLoading, setIsLoading] = useState(false);
  const [hasMore, setHasMore] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [pagesLoaded, setPagesLoaded] = useState(0);
  // TODO: sentinel ref, observer ref, loading ref

  // TODO: fetchPage function
  // TODO: useEffect for initial fetch
  // TODO: useEffect for IntersectionObserver

  return (
    <div>
      <p data-testid="pages-loaded" className="feed__meta">
        Pages loaded: {pagesLoaded}
      </p>

      <div data-testid="feed" className="feed">
        {posts.map(post => (
          <article key={post.id} data-testid={`post-${post.id}`} className="feed__post">
            <h3 className="feed__title">{post.title}</h3>
            <p className="feed__body">{post.body}</p>
            <span className="feed__author">— {post.author}</span>
          </article>
        ))}

        {isLoading && (
          <div data-testid="loading-spinner" className="feed__loading">Loading…</div>
        )}

        {error && (
          <div data-testid="load-error" className="feed__error">
            {error}
            <button data-testid="retry-btn" className="feed__retry">Retry</button>
          </div>
        )}

        {!hasMore && posts.length > 0 && (
          <div data-testid="end-message" className="feed__end">No more posts</div>
        )}

        {/* Sentinel for IntersectionObserver */}
        <div data-testid="sentinel" style={{ height: 1 }} />
      </div>
    </div>
  );
};

.feed__meta {
  font-size: 0.8125rem;
  color: #6b7280;
  margin-bottom: 0.75rem;
}

.feed {
  display: flex;
  flex-direction: column;
  gap: 0.75rem;
}

.feed__post {
  padding: 1rem;
  border: 1px solid #e5e7eb;
  border-radius: 0.5rem;
}

.feed__title {
  font-size: 0.9375rem;
  margin: 0 0 0.5rem;
}

.feed__body {
  font-size: 0.8125rem;
  color: #4b5563;
  margin: 0 0 0.5rem;
  line-height: 1.5;
}

.feed__author {
  font-size: 0.75rem;
  color: #9ca3af;
}

.feed__loading {
  text-align: center;
  padding: 1rem;
  color: #3b82f6;
  font-size: 0.875rem;
}

.feed__error {
  text-align: center;
  padding: 1rem;
  color: #ef4444;
  font-size: 0.875rem;
}

