  display: inline-block;
  margin-top: 0.5rem;
  padding: 0.25rem 0.5rem;
  border: none;
  border-radius: 0.25rem;
  background: #ef4444;
  color: white;
  cursor: pointer;
  font-size: 0.8125rem;
}

