import { render, screen, fireEvent, waitFor } from '@testing-library/react';
import '@testing-library/jest-dom';
import React from 'react';

let fetchMock: jest.Mock;
let observerCallback: IntersectionObserverCallback;
let observedElements: Element[] = [];

const mockObserver = jest.fn((cb: IntersectionObserverCallback) => {
  observerCallback = cb;
  return {
    observe: jest.fn((el: Element) => { observedElements.push(el); }),
    unobserve: jest.fn(),
    disconnect: jest.fn(),
  };
});

window.IntersectionObserver = mockObserver as any;

function triggerIntersect() {
  if (observedElements.length > 0 && observerCallback) {
    observerCallback(
      [{ isIntersecting: true, target: observedElements[observedElements.length - 1] } as any],
      {} as IntersectionObserver
    );
  }
}

const makePosts = (page: number, size: number, totalPages: number) => ({
  data: Array.from({ length: size }, (_, i) => ({
    id: (page - 1) * size + i + 1,
    title: `Post ${(page - 1) * size + i + 1}`,
    body: 'Content here',
    author: 'Author',
  })),
  hasMore: page < totalPages,
});

beforeEach(() => {
  observedElements = [];
  fetchMock = jest.fn((url: string) => {
    const params = new URL(url, 'http://localhost').searchParams;
    const page = parseInt(params.get('page') || '1');
    return Promise.resolve({
      ok: true,
      json: () => Promise.resolve(makePosts(page, 10, 3)),
    });
  });
  global.fetch = fetchMock;
});

afterEach(() => {
  jest.restoreAllMocks();
});

import App from './App';

describe('Infinite Scroll Feed', () => {
  it('loads first page on mount', async () => {
    render(<App />);
    await waitFor(() => {
      expect(screen.getByTestId('post-1')).toBeInTheDocument();
    });
  });

  it('shows pages loaded count', async () => {
    render(<App />);
    await waitFor(() => {
      expect(screen.getByTestId('pages-loaded')).toHaveTextContent('1');
    });
  });

  it('uses IntersectionObserver', async () => {
    render(<App />);
    expect(mockObserver).toHaveBeenCalled();
  });

  it('has sentinel element', () => {
    render(<App />);
    expect(screen.getByTestId('sentinel')).toBeInTheDocument();
  });

  it('loads more on intersection', async () => {
    render(<App />);
    await waitFor(() => expect(screen.getByTestId('post-1')).toBeInTheDocument());
    triggerIntersect();
    await waitFor(() => {
      expect(screen.getByTestId('post-11')).toBeInTheDocument();
    });
  });

  it('shows end message when no more pages', async () => {
    render(<App />);
    await waitFor(() => expect(screen.getByTestId('post-1')).toBeInTheDocument());
    triggerIntersect();
    await waitFor(() => expect(screen.getByTestId('post-11')).toBeInTheDocument());
    triggerIntersect();
    await waitFor(() => expect(screen.getByTestId('post-21')).toBeInTheDocument());
    await waitFor(() => {
      expect(screen.getByTestId('end-message')).toBeInTheDocument();
    });
  });
});

