import React, { useState, useEffect, useRef, useCallback } from 'react';
import './styles.css';

interface Post {
  id: number;
  title: string;
  body: string;
  author: string;
}

interface FeedProps {
  apiUrl: string;
  pageSize: number;
}

export const Feed: React.FC<FeedProps> = ({ apiUrl, pageSize }) => {
  const [posts, setPosts] = useState<Post[]>([]);
  const [page, setPage] = useState(1);
  const [isLoading, setIsLoading] = useState(false);
  const [hasMore, setHasMore] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [pagesLoaded, setPagesLoaded] = useState(0);
  const sentinelRef = useRef<HTMLDivElement>(null);
  const observerRef = useRef<IntersectionObserver | null>(null);
  const loadingRef = useRef(false);
  const hasMoreRef = useRef(true);
  const pageRef = useRef(1);

  const fetchPage = useCallback(async (p: number) => {
    if (loadingRef.current || !hasMoreRef.current) return;
    loadingRef.current = true;
    setIsLoading(true);
    setError(null);

    try {
      const res = await fetch(`${apiUrl}?page=${p}&limit=${pageSize}`);
      if (!res.ok) throw new Error('Failed to load');
      const json = await res.json();
      setPosts(prev => [...prev, ...json.data]);
      setPagesLoaded(prev => prev + 1);
      setHasMore(json.hasMore);
      hasMoreRef.current = json.hasMore;
      pageRef.current = p + 1;
      setPage(p + 1);
    } catch (err: any) {
      setError(err.message || 'Error loading posts');
    } finally {
      setIsLoading(false);
      loadingRef.current = false;
    }
  }, [apiUrl, pageSize]);

  // Initial fetch
  useEffect(() => {
    fetchPage(1);
  }, [fetchPage]);

  // IntersectionObserver
  useEffect(() => {
    observerRef.current = new IntersectionObserver(
      (entries) => {
        if (entries[0]?.isIntersecting && !loadingRef.current && hasMoreRef.current) {
          fetchPage(pageRef.current);
        }
      },
      { rootMargin: '200px' }
    );

    if (sentinelRef.current) {
      observerRef.current.observe(sentinelRef.current);
    }

    return () => {
      observerRef.current?.disconnect();
    };
  }, [fetchPage]);

  const handleRetry = useCallback(() => {
    fetchPage(pageRef.current);
  }, [fetchPage]);

  return (
    <div>
      <p data-testid="pages-loaded" className="feed__meta">
        Pages loaded: {pagesLoaded}
      </p>

      <div data-testid="feed" className="feed">
        {posts.map(post => (
          <article key={post.id} data-testid={`post-${post.id}`} className="feed__post">
            <h3 className="feed__title">{post.title}</h3>
            <p className="feed__body">{post.body}</p>
            <span className="feed__author">— {post.author}</span>
          </article>
        ))}

        {isLoading && (
          <div data-testid="loading-spinner" className="feed__loading">Loading…</div>
        )}

        {error && (
          <div data-testid="load-error" className="feed__error">
            {error}
            <button data-testid="retry-btn" className="feed__retry" onClick={handleRetry}>Retry</button>
          </div>
        )}

        {!hasMore && posts.length > 0 && (
          <div data-testid="end-message" className="feed__end">No more posts</div>
        )}

        <div ref={sentinelRef} data-testid="sentinel" style={{ height: 1 }} />
      </div>
    </div>
  );
};
